#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 524290
int countComponents(int n, char **grid) {
    int count = 0;
    int **unfolded = (int **)malloc(8 * (1 << (n - 3)) * sizeof(int *));
    for (int i = 0; i < 8 * (1 << (n - 3)); i++) {
        unfolded[i] = (int *)malloc(8 * (1 << (n - 3)) * sizeof(int));
    }
    for (int i = 0; i < 8; i++) {
        for (int j = 0; j < 8; j++) {
            unfolded[i][j] = grid[i][j] - '0';
        }
    }
    for (int k = 0; k < n - 3; k++) {
        for (int i = 0; i < 8 * (1 << k); i++) {
            for (int j = 0; j < 8 * (1 << k); j++) {
                unfolded[i * 2][j * 2] = unfolded[i][j];
                unfolded[i * 2 + 1][j * 2] = unfolded[i][j];
                unfolded[i * 2][j * 2 + 1] = unfolded[i][j];
                unfolded[i * 2 + 1][j * 2 + 1] = unfolded[i][j];
            }
        }
    }
    int **visited = (int **)malloc(8 * (1 << (n - 3)) * sizeof(int *));
    for (int i = 0; i < 8 * (1 << (n - 3)); i++) {
        visited[i] = (int *)malloc(8 * (1 << (n - 3)) * sizeof(int));
    }
    for (int i = 0; i < 8 * (1 << (n - 3)); i++) {
        for (int j = 0; j < 8 * (1 << (n - 3)); j++) {
            visited[i][j] = 0;
        }
    }
    for (int i = 0; i < 8 * (1 << (n - 3)); i++) {
        for (int j = 0; j < 8 * (1 << (n - 3)); j++) {
            if (unfolded[i][j] == 1 && visited[i][j] == 0) {
                count++;
                floodFill(unfolded, visited, i, j, 8 * (1 << (n - 3)), 8 * (1 << (n - 3)));
            }
        }
    }
    return count % MOD;
}
void floodFill(int **grid, int **visited, int x, int y, int n, int m) {
    if (x < 0 || x >= n || y < 0 || y >= m || visited[x][y] == 1 || grid[x][y] == 0) {
        return;
    }
    visited[x][y] = 1;
    floodFill(grid, visited, x + 1, y, n, m);
    floodFill(grid, visited, x - 1, y, n, m);
    floodFill(grid, visited, x, y + 1, n, m);
    floodFill(grid, visited, x, y - 1, n, m);
}
int main() {
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        int n;
        scanf("%d", &n);
        char **grid = (char **)malloc(8 * sizeof(char *));
        for (int j = 0; j < 8; j++) {
            grid[j] = (char *)malloc(9 * sizeof(char));
        }
        for (int j = 0; j < 8; j++) {
            scanf("%s", grid[j]);
        }
        printf("%d\n", countComponents(n, grid));
    }
    return 0;
}

